// ── Nav ──────────────────────────────────────────────────────────────────────
const Nav = ({ navigate, path }) => {
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => { const h = () => setScrolled(window.scrollY > 50); window.addEventListener('scroll', h); return () => window.removeEventListener('scroll', h); }, []);
  const go = (p) => { setOpen(false); navigate(p); };
  const links = [{ n: 'Home', p: '/' }, { n: 'Services', p: '/services' }, { n: 'About', p: '/about' }];
  const active = (p) => path === p ? '#FF6B2A' : '#FAFAFA';
  return (
    <>
      <nav style={{ position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100, padding: scrolled ? '0.875rem 3rem' : '1.5rem 3rem', background: scrolled ? 'rgba(10,10,10,0.92)' : 'transparent', backdropFilter: scrolled ? 'blur(20px)' : 'none', borderBottom: scrolled ? '1px solid rgba(255,255,255,0.05)' : 'none', transition: 'all 0.3s ease', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }} className="container-px">
        <div onClick={() => go('/')} style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <Logo height={42} />
          <span style={{ ...arch(700), fontSize: '0.95rem', letterSpacing: '-0.02em' }}>OVC Elevated Marketing</span>
        </div>
        <div className="nav-desktop" style={{ display: 'flex', gap: '2.5rem', alignItems: 'center' }}>
          {links.map(l => <span key={l.n} onClick={() => go(l.p)} className="nav-link" style={{ ...arch(500), fontSize: '0.9rem', cursor: 'pointer', color: active(l.p) }}>{l.n}</span>)}
          <span onClick={() => go('/contact')} className="nav-link" style={{ ...arch(500), fontSize: '0.9rem', cursor: 'pointer', color: active('/contact') }}>Contact Us</span>
          <button onClick={() => go('/contact')} className="btn-primary" style={{ padding: '0.625rem 1.25rem', fontSize: '0.85rem' }}>Start Project <ArrowUpRight size={14} /></button>
        </div>
        <div className="mobile-only" onClick={() => setOpen(!open)} style={{ cursor: 'pointer', zIndex: 102 }}>
          {open ? <X size={24} /> : <Menu size={24} />}
        </div>
      </nav>
      {open && (
        <div style={{ position: 'fixed', inset: 0, background: '#0A0A0A', zIndex: 101, display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', gap: '2rem' }}>
          {[...links, { n: 'Contact Us', p: '/contact' }].map(l => (
            <span key={l.n} onClick={() => go(l.p)} style={{ ...arch(800), fontSize: '3rem', cursor: 'pointer', letterSpacing: '-0.04em', color: active(l.p) }}>{l.n}</span>
          ))}
          <button onClick={() => go('/contact')} className="btn-primary" style={{ marginTop: '1rem' }}>Start Project <ArrowUpRight size={14} /></button>
        </div>
      )}
    </>
  );
};

