// ── Global CSS ────────────────────────────────────────────────────────────────
const GlobalStyles = () => (
  <style>{`
    @import url('https://fonts.googleapis.com/css2?family=Archivo:wght@400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500&display=swap');
    * { margin:0; padding:0; box-sizing:border-box; }
    body { background:#0A0A0A; color:#FAFAFA; -webkit-font-smoothing:antialiased; }
    @keyframes marquee { 0% { transform:translateX(0); } 100% { transform:translateX(-50%); } }
    @keyframes blob { 0%,100% { transform:translate(0,0) scale(1); } 33% { transform:translate(30px,-30px) scale(1.1); } 66% { transform:translate(-20px,20px) scale(0.95); } }
    @keyframes pulse { 0%,100% { opacity:0.4; transform:scale(1); } 50% { opacity:0.8; transform:scale(1.05); } }
    .service-card { transition:all 0.4s cubic-bezier(0.4,0,0.2,1); }
    .service-card:hover { background:linear-gradient(90deg, rgba(255,107,42,0.05) 0%, transparent 100%); padding-left:2rem; }
    .service-card:hover .service-arrow { transform:translate(8px,-8px); color:#FF6B2A; }
    .service-card:hover .service-num { color:#FF6B2A; }
    .service-arrow { transition:all 0.4s cubic-bezier(0.4,0,0.2,1); }
    .service-num { transition:color 0.4s ease; }
    .nav-link { position:relative; transition:color 0.3s ease; cursor:pointer; }
    .nav-link::after { content:''; position:absolute; bottom:-4px; left:0; width:0; height:1px; background:#FF6B2A; transition:width 0.3s ease; }
    .nav-link:hover::after { width:100%; }
    .nav-link:hover { color:#FF6B2A; }
    .btn-primary { display:inline-flex; align-items:center; gap:0.5rem; padding:1rem 1.75rem; background:#FF6B2A; color:#0A0A0A; border:none; border-radius:100px; font-family:'Archivo',sans-serif; font-weight:600; font-size:0.95rem; cursor:pointer; transition:all 0.3s ease; }
    .btn-primary:hover { background:#FAFAFA; transform:translateY(-2px); box-shadow:0 10px 30px rgba(255,107,42,0.3); }
    .btn-secondary { display:inline-flex; align-items:center; gap:0.5rem; padding:1rem 1.75rem; background:transparent; color:#FAFAFA; border:1px solid rgba(255,255,255,0.2); border-radius:100px; font-family:'Archivo',sans-serif; font-weight:500; font-size:0.95rem; cursor:pointer; transition:all 0.3s ease; }
    .btn-secondary:hover { border-color:#FAFAFA; background:rgba(255,255,255,0.05); }
    .team-card:hover, .danny-card:hover { transform:translateY(-8px); }
    .value-card { padding:2.5rem; background:#141414; border:1px solid rgba(255,255,255,0.05); border-radius:16px; transition:all 0.4s ease; }
    .value-card:hover { background:#1A1A1A; border-color:rgba(255,107,42,0.3); transform:translateY(-4px); }
    input:focus, textarea:focus { border-color:#FF6B2A !important; outline:none; }
    input::placeholder, textarea::placeholder { color:rgba(250,250,250,0.4); }
    @media (max-width:768px) {
      .nav-desktop { display:none !important; }
      .mobile-only { display:block !important; }
      .hero-grid, .about-grid, .contact-grid, .footer-grid { grid-template-columns:1fr !important; gap:3rem !important; }
      .values-grid { grid-template-columns:1fr !important; }
      .team-grid { grid-template-columns:1fr 1fr !important; }
      .hero-logo-container { order:-1; max-width:260px; margin:0 auto 2rem; }
      .service-row { flex-direction:column !important; align-items:flex-start !important; gap:1rem !important; }
      .form-row { grid-template-columns:1fr !important; }
      .container-px { padding-left:1.5rem !important; padding-right:1.5rem !important; }
    }
    .mobile-only { display:none; }
  `}</style>
);

// ── App ───────────────────────────────────────────────────────────────────────
export default function App() {
  const { path, navigate } = useRouter();
  const Page = () => {
    if (path === '/services') return <ServicesPage navigate={navigate} />;
    if (path === '/about') return <AboutPage navigate={navigate} />;
    if (path === '/contact') return <ContactPage />;
    return <Home navigate={navigate} />;
  };
  return (
    <div style={{ background: '#0A0A0A', color: '#FAFAFA', fontFamily: 'Archivo, sans-serif', minHeight: '100vh' }}>
      <GlobalStyles />
      <Nav navigate={navigate} path={path} />
      <Page />
      <Footer navigate={navigate} />
    </div>
  );
}
